sql:
SELECT measurement_type, AVG(avg) AS avg_measurement
FROM assay_data
GROUP BY measurement_type;

SELECT assay_data_id, avg
FROM assay_data
WHERE measurement_type = 'absorbance';

SELECT assay_data_id, well_id, time_point_id, avg, stdev,
       MAX(avg) OVER () AS highest_average
FROM assay_data;

SELECT well_id, time_point_id, avg, stdev, tx, measurement_type
FROM assay_data
WHERE avg = (SELECT MIN(avg) FROM assay_data);

SELECT ROUND(AVG(avg), 2) AS average_value
FROM assay_data
WHERE method = 'ELISA';

